(419, 13, 'XYXX Men''s Micro Modal Innerwear Trunks', 'Ultra-soft Micro Modal trunks with anti-odour technology. Premium innerwear for all-day comfort.', 599.00, 250, 4.6, 9800, '{"Brand": "XYXX", "Material": "Micro Modal", "Type": "Trunks/Innerwear", "Feature": "Anti-Odour"}'),
(420, 13, 'Amazon Symbol Men''s Slim Fit T-Shirt', 'Everyday slim-fit crewneck t-shirt from Amazon''s own Symbol brand. Soft cotton, smart casual.', 499.00, 300, 4.2, 7200, '{"Brand": "Amazon Brand - Symbol", "Fit": "Slim Fit", "Material": "Cotton", "Type": "T-Shirt", "Neck": "Crew Neck"}'),
(421, 13, 'Bigbanana Men''s Plus Size Casual Shirt', 'Stylish casual shirt available in extended plus sizes. Relaxed fit, bold prints, premium feel.', 899.00, 100, 4.3, 2100, '{"Brand": "Bigbanana", "Fit": "Relaxed Fit", "Material": "Cotton Blend", "Type": "Casual Shirt", "Size Range": "Plus Size"}'),
(422, 13, 'Aventura Outfitters Men''s Outdoor Cargo Shirt', 'Rugged cargo shirt with multiple pockets. Ideal for outdoor adventures, trekking and travel.', 1299.00, 80, 4.4, 1500, '{"Brand": "Aventura Outfitters", "Fit": "Regular Fit", "Material": "Cotton Twill", "Type": "Cargo Shirt", "Pockets": "Multiple"}'),
(423, 13, 'U.S. Polo Assn. Men''s Polo T-Shirt', 'Classic polo t-shirt with signature US Polo Assn. logo. Soft pique fabric with ribbed collar.', 999.00, 200, 4.5, 15600, '{"Brand": "U.S. Polo Assn.", "Fit": "Regular Fit", "Material": "Pique Cotton", "Type": "Polo T-Shirt", "Collar": "Ribbed Polo"}'),
