(426, 13, 'Lymio Women''s Solid A-Line Kurti', 'Elegant solid A-line kurti in soft rayon fabric. Simple and chic for daily Indian wear.', 549.00, 200, 4.2, 3900, '{"Brand": "Lymio", "Type": "A-Line Kurti", "Print": "Solid", "Fabric": "Rayon", "Occasion": "Daily Wear"}'),
