(429, 13, 'U.S. Polo Assn. Men''s Slim Fit Jeans', 'Slim fit 5-pocket jeans from U.S. Polo Assn. with stretch denim for easy movement.', 1599.00, 120, 4.5, 8900, '{"Brand": "U.S. Polo Assn.", "Fit": "Slim Fit", "Material": "Stretch Denim", "Type": "Jeans", "Pockets": "5"}'),
(430, 13, 'Lux Cozi Men''s Long Trunk (Pack of 2)', 'Comfortable long-cut trunks from Lux Cozi. Soft cotton fabric, wide elasticated waistband.', 319.00, 380, 4.3, 8200, '{"Brand": "Lux Cozi", "Material": "Cotton", "Pack": "2 Pieces", "Type": "Long Trunk", "Waistband": "Elasticated"}'),
(431, 13, 'BAGHADBILLO Men''s Quirky Printed Shirt', 'Fun and expressive printed shirt with unique quirky artwork. Stand out from the crowd.', 649.00, 150, 4.1, 1800, '{"Brand": "BAGHADBILLO", "Fit": "Regular Fit", "Material": "Cotton", "Type": "Printed Shirt", "Style": "Quirky"}'),
(432, 13, 'KAJARU Men''s Solid Casual T-Shirt (Pack of 2)', 'Pack of 2 solid colour round-neck t-shirts. Soft jersey fabric, everyday wardrobe essential.', 599.00, 220, 4.2, 4700, '{"Brand": "KAJARU", "Fit": "Regular Fit", "Material": "Jersey Knit", "Pack": "2 T-Shirts", "Type": "Casual T-Shirt"}'),
(433, 13, 'Alan Jones Men''s Bomber Jacket', 'Stylish bomber jacket with ribbed cuffs and collar. Lightweight, trendy and season-versatile.', 1999.00, 60, 4.4, 1200, '{"Brand": "Alan Jones Clothing", "Type": "Bomber Jacket", "Material": "Polyester", "Closure": "Zipper", "Style": "Casual"}'),
(434, 13, 'Van Heusen Men''s Premium Casual Shirt', 'Weekend-ready casual shirt from Van Heusen in soft, relaxed fabric. Versatile and smart casual.', 1499.00, 110, 4.5, 6800, '{"Brand": "Van Heusen", "Fit": "Regular Fit", "Material": "Cotton Blend", "Type": "Casual Shirt", "Occasion": "Casual/Weekend"}'),
(435, 13, 'London Hills Men''s Slim Fit Shirt', 'Smart affordable slim-fit shirt. Clean lines, button-down collar and easy-care fabric.', 799.00, 160, 4.2, 3100, '{"Brand": "London Hills", "Fit": "Slim Fit", "Material": "Cotton Blend", "Type": "Casual Shirt", "Care": "Easy-Care"}'),
(436, 13, 'LEOTUDE Men''s Zip-Up Track Jacket', 'Comfortable zip-up track jacket for gym, jogging and casual outings. Side pockets, rib cuffs.', 999.00, 130, 4.4, 3800, '{"Brand": "LEOTUDE", "Type": "Track Jacket", "Closure": "Full Zip", "Material": "Polyester Blend", "Pockets": "Side Pockets"}'),
(437, 13, 'LEOTUDE Men''s Slim Fit Jogger Pants', 'Slim tapered jogger pants with drawstring waist. Four-way stretch for gym and leisure wear.', 899.00, 140, 4.4, 4200, '{"Brand": "LEOTUDE", "Fit": "Slim Tapered", "Material": "Polyester Blend", "Type": "Jogger Pants", "Stretch": "4-Way"}'),
